'use client'

import { useState, useEffect, useCallback, useRef } from 'react'

export type PomodoroPhase = 'work' | 'shortBreak' | 'longBreak'

export interface PomodoroState {
  timeLeft: number
  phase: PomodoroPhase
  sessionCount: number
  isRunning: boolean
  isPaused: boolean
}

export interface PomodoroConfig {
  workDuration: number       // in minutes (default: 25)
  shortBreakDuration: number // in minutes (default: 5)
  longBreakDuration: number  // in minutes (default: 15)
  sessionsUntilLongBreak: number // default: 4
}

const DEFAULT_CONFIG: PomodoroConfig = {
  workDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  sessionsUntilLongBreak: 4,
}

export function usePomodoro(
  config: PomodoroConfig = DEFAULT_CONFIG,
  onTick?: (state: PomodoroState) => void,
  onPhaseChange?: (phase: PomodoroPhase, sessionCount: number) => void
) {
  const [timeLeft, setTimeLeft] = useState(config.workDuration * 60)
  const [phase, setPhase] = useState<PomodoroPhase>('work')
  const [sessionCount, setSessionCount] = useState(0)
  const [isRunning, setIsRunning] = useState(false)
  const [isPaused, setIsPaused] = useState(false)

  const intervalRef = useRef<NodeJS.Timeout | null>(null)
  const configRef = useRef(config)

  // Keep config ref updated
  useEffect(() => {
    configRef.current = config
  }, [config])

  const getPhaseDuration = useCallback((p: PomodoroPhase): number => {
    const cfg = configRef.current
    switch (p) {
      case 'work':
        return cfg.workDuration * 60
      case 'shortBreak':
        return cfg.shortBreakDuration * 60
      case 'longBreak':
        return cfg.longBreakDuration * 60
    }
  }, [])

  const getNextPhase = useCallback((): PomodoroPhase => {
    const cfg = configRef.current
    if (phase === 'work') {
      const newSessionCount = sessionCount + 1
      if (newSessionCount % cfg.sessionsUntilLongBreak === 0) {
        return 'longBreak'
      }
      return 'shortBreak'
    }
    return 'work'
  }, [phase, sessionCount])

  const stopTimer = useCallback(() => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current)
      intervalRef.current = null
    }
  }, [])

  const tick = useCallback(() => {
    setTimeLeft((prev) => {
      if (prev <= 1) {
        return 0
      }
      return prev - 1
    })
  }, [])

  useEffect(() => {
    if (isRunning && !isPaused) {
      intervalRef.current = setInterval(tick, 1000)
    } else {
      stopTimer()
    }
    return stopTimer
  }, [isRunning, isPaused, tick, stopTimer])

  // Handle phase transitions
  useEffect(() => {
    if (timeLeft === 0 && isRunning) {
      const nextPhase = getNextPhase()
      const newSessionCount = phase === 'work' ? sessionCount + 1 : sessionCount

      setPhase(nextPhase)
      setSessionCount(newSessionCount)
      setTimeLeft(getPhaseDuration(nextPhase))

      onPhaseChange?.(nextPhase, newSessionCount)
    }
  }, [timeLeft, isRunning, phase, sessionCount, getNextPhase, getPhaseDuration, onPhaseChange])

  // Notify on tick
  useEffect(() => {
    if (isRunning) {
      onTick?.({ timeLeft, phase, sessionCount, isRunning, isPaused })
    }
  }, [timeLeft, phase, sessionCount, isRunning, isPaused, onTick])

  const start = useCallback(() => {
    setIsRunning(true)
    setIsPaused(false)
  }, [])

  const pause = useCallback(() => {
    setIsPaused(true)
  }, [])

  const resume = useCallback(() => {
    setIsPaused(false)
  }, [])

  const reset = useCallback(() => {
    stopTimer()
    setIsRunning(false)
    setIsPaused(false)
    setTimeLeft(getPhaseDuration(phase))
  }, [phase, getPhaseDuration, stopTimer])

  const skip = useCallback(() => {
    const nextPhase = getNextPhase()
    const newSessionCount = phase === 'work' ? sessionCount + 1 : sessionCount
    setPhase(nextPhase)
    setSessionCount(newSessionCount)
    setTimeLeft(getPhaseDuration(nextPhase))
    onPhaseChange?.(nextPhase, newSessionCount)
  }, [phase, sessionCount, getNextPhase, getPhaseDuration, onPhaseChange])

  const switchPhase = useCallback((newPhase: PomodoroPhase) => {
    stopTimer()
    setIsRunning(false)
    setIsPaused(false)
    setPhase(newPhase)
    setTimeLeft(getPhaseDuration(newPhase))
  }, [getPhaseDuration, stopTimer])

  const resetAll = useCallback(() => {
    stopTimer()
    setIsRunning(false)
    setIsPaused(false)
    setPhase('work')
    setSessionCount(0)
    setTimeLeft(config.workDuration * 60)
  }, [config.workDuration, stopTimer])

  return {
    // State
    timeLeft,
    phase,
    sessionCount,
    isRunning,
    isPaused,
    // Actions
    start,
    pause,
    resume,
    reset,
    skip,
    switchPhase,
    resetAll,
    // Helpers
    formatTime: (seconds: number) => {
      const mins = Math.floor(seconds / 60)
      const secs = seconds % 60
      return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`
    },
  }
}
